45	/**
46	 * Fetches career guidance roles filtered by Trait AND Department.
47	 * * @param traitCode - The trait string (e.g. "DI")
48	 * @param departmentId - The department degree ID (e.g. 101)
49	 */
50	export async function getCareerGuidanceByTrait(
51	  traitCode: string,
52	  departmentId: number | undefined,
53	): Promise<CareerRoleData[]> {
54	  logger.info(
55	    `\n[DB-DEBUG] 🚀 Starting fetch for trait: "${traitCode}" & Dept ID: ${departmentId}`,
56	  );
57	
58	  if (process.env.MOCK_DB === 'true') {
59	    logger.info('[DB-DEBUG] Mocking Career Guidance');
60	    return [];
61	  }
62	
63	  const client = await getPool().connect();
64	
65	  try {
66	    // 1. Get Trait ID
67	    const traitQuery = `SELECT id FROM personality_traits WHERE code = $1 AND is_active = true LIMIT 1;`;
68	    const traitResult = await client.query(traitQuery, [traitCode]);
69	
70	    if (traitResult.rows.length === 0) {
71	      logger.warn(
72	        `[DB-DEBUG] ❌ No entry found in 'personality_traits' for code '${traitCode}'.`,
73	      );
74	      return [];
75	    }
76	
77	    const traitId = traitResult.rows[0].id;
78	    logger.info(
79	      `[DB-DEBUG] ✅ Found Trait ID: ${traitId} for Trait Code: ${traitCode}`,
80	    );
81	
82	    // 2. Get Career Roles (Filtered by Trait AND Department)
83	    // Note: Using 'department_degree_id' matching the table schema.
84	    const rolesQuery = `
85	            SELECT id, career_role_name, short_description 
86	            FROM career_roles 
87	            WHERE trait_id = $1 
88	            AND department_degree_id = $2
89	            AND is_active = true 
90	            AND is_deleted = false
91	            ORDER BY id ASC;
92	        `;
93	
94	    const rolesResult = await client.query(rolesQuery, [traitId, departmentId]);
95	
96	    if (rolesResult.rows.length === 0) {
97	      logger.warn(
98	        `[DB-DEBUG] ❌ No active career roles found for Trait ID ${traitId} AND Dept ID ${departmentId}.`,
99	      );
100	      // Optional: Fallback logic could go here if you wanted to show generic roles instead
101	      return [];
102	    }
103	
104	    logger.info(
105	      `[DB-DEBUG] ✅ Found ${rolesResult.rows.length} Roles matching criteria.`,
106	    );
107	
108	    // 3. Loop through roles to get Details & Tools
109	    const results: CareerRoleData[] = [];
110	
111	    for (const role of rolesResult.rows) {
112	      // A. Fetch Guidance Sections
113	      const sectionsQuery = `
114	                SELECT section_content FROM career_role_guidance_sections 
115	                WHERE career_role_id = $1 AND is_active = true AND is_deleted = false
116	                ORDER BY id ASC;
117	            `;
118	      const sectionsResult = await client.query(sectionsQuery, [role.id]);
119	
120	      let guidanceSections: GuidanceSectionJSON[] = [];
121	      if (sectionsResult.rows.length > 0) {
122	        guidanceSections = sectionsResult.rows[0].section_content;
123	      }
124	
125	      // B. Fetch Tools
126	      const toolsQuery = `SELECT tool_name FROM career_role_tools WHERE career_role_id = $1 AND is_active = true AND is_deleted = false;`;
127	      const toolsResult = await client.query(toolsQuery, [role.id]);
128	      const tools = toolsResult.rows.map((row) => row.tool_name);
129	
130	      results.push({
131	        roleName: role.career_role_name,
132	        shortDescription: role.short_description,
133	        guidanceSections,
134	        tools,
135	      });
136	    }
137	
138	    return results;
139	  } catch (error) {
140	    logger.error('[DB-DEBUG] ❌ SQL ERROR:', error);
141	    throw error;
142	  } finally {
143	    client.release();
144	    logger.info(`[DB-DEBUG] DB Connection released.\n`);
145	  }
146	}
