148	export async function getCompatibilityMatrixDetails(
149	  traitCode: string,
150	  schoolStreamId: number | undefined,
151	): Promise<CourseCompatibility[]> {
152	  logger.info(`\n[DB-DEBUG] 🚀 Starting fetch for trait: "${traitCode}"`);
153	  logger.info(
154	    `\n[DB-DEBUG] 🚀 Starting fetch for schoolStreamId: "${schoolStreamId}"`,
155	  );
156	
157	  if (process.env.MOCK_DB === 'true') {
158	    logger.info('[DB-DEBUG] Mocking Compatibility Matrix');
159	    return [];
160	  }
161	
162	  const client = await getPool().connect();
163	
164	  try {
165	    // 1. Get Trait ID
166	    const traitQuery = `SELECT id FROM personality_traits WHERE code = $1 AND is_active = true LIMIT 1;`;
167	    const traitResult = await client.query(traitQuery, [traitCode]);
168	
169	    if (traitResult.rows.length === 0) {
170	      logger.warn(
171	        `[DB-DEBUG] ❌ No entry found in 'personality_traits' for code '${traitCode}'.`,
172	      );
173	      return [];
174	    }
175	
176	    const traitId = traitResult.rows[0].id;
177	    logger.info(`[DB-DEBUG] ✅ Found Trait ID: ${traitId}`);
178	
179	    // 2. Get Courses (Filtered by Trait, joined through school_stream_departments)
180	    // trait_based_course_details.school_stream_department_id -> school_stream_departments.id
181	    // school_stream_departments.school_stream_id -> the stream we filter by
182	    if (schoolStreamId) {
183	      // --- HSC: Specific Stream, Top 10 per Department ---
184	      const rolesQuery = `
185	                WITH RankedCourses AS (
186	                    SELECT 
187	                        tcd.course_name, 
188	                        tcd.compatibility_percentage, 
189	                        tcd.notes,
190	                        ssd.name AS department_name,
191	                        ssd.display_order,
192	                        ROW_NUMBER() OVER (
193	                            PARTITION BY ssd.id 
194	                            ORDER BY tcd.compatibility_percentage DESC, tcd.id ASC
195	                        ) as rank
196	                    FROM trait_based_course_details tcd
197	                    JOIN school_stream_departments ssd ON tcd.school_stream_department_id = ssd.id
198	                    WHERE tcd.trait_id = $1
199	                      AND ssd.school_stream_id = $2
200	                )
201	                SELECT 
202	                    course_name, 
203	                    compatibility_percentage, 
204	                    notes, 
205	                    department_name
206	                FROM RankedCourses
207	                ORDER BY display_order ASC, compatibility_percentage DESC;
208	            `;
209	
210	      const rolesResult = await client.query(rolesQuery, [
211	        traitId,
212	        schoolStreamId,
213	      ]);
214	
215	      if (rolesResult.rows.length === 0) {
216	        logger.warn(
217	          `[DB-DEBUG] ❌ No Recommended Courses found for Trait ID ${traitId}.`,
218	        );
219	        return [];
220	      }
221	
222	      return rolesResult.rows;
223	    } else {
224	      // --- SSLC: All Streams, Top 10 per Department ---
225	      logger.info(
226	        '[DB-DEBUG] ℹ️ SSLC Case: Fetching Top 10 per department across streams',
227	      );
228	
229	      const multiStreamQuery = `
230	                WITH RankedCourses AS (
231	                    SELECT 
232	                        tcd.course_name, 
233	                        tcd.compatibility_percentage, 
234	                        tcd.notes,
235	                        ssd.name AS department_name,
236	                        ssd.display_order,
237	                        ssd.school_stream_id,
238	                        ROW_NUMBER() OVER (
239	                            PARTITION BY ssd.id 
240	                            ORDER BY tcd.compatibility_percentage DESC, tcd.id ASC
241	                        ) as rank
242	                    FROM trait_based_course_details tcd
243	                    JOIN school_stream_departments ssd ON tcd.school_stream_department_id = ssd.id
244	                    WHERE tcd.trait_id = $1 
245	                    AND ssd.school_stream_id IN (1, 2, 3, 4, 5, 6) 
246	                )
247	                SELECT 
248	                    course_name, 
249	                    compatibility_percentage, 
250	                    notes, 
251	                    department_name,
252	                    school_stream_id
253	                FROM RankedCourses
254	                ORDER BY display_order ASC, compatibility_percentage DESC;
255	            `;
256	
257	      const result = await client.query(multiStreamQuery, [traitId]);
258	
259	      if (result.rows.length === 0) {
260	        return [];
261	      }
262	
263	      // Transform: Append Stream Name to department_name for SSLC context
264	      const streamNames: Record<number, string> = {
265	        1: 'PCMB',
266	        2: 'PCB',
267	        3: 'PCM',
268	        4: 'PCBZ',
269	        5: 'Commerce',
270	        6: 'Humanities',
271	      };
272	
273	      return result.rows.map((row) => ({
274	        course_name: row.course_name,
275	        compatibility_percentage: row.compatibility_percentage,
276	        notes: row.notes,
277	        department_name: `${row.department_name} (${streamNames[row.school_stream_id] || 'General'})`,
278	      }));
279	    }
280	  } catch (error) {
281	    logger.error('[DB-DEBUG] ❌ SQL ERROR:', error);
282	    throw error;
283	  } finally {
284	    client.release();
285	    logger.info(`[DB-DEBUG] DB Connection released.\n`);
286	  }
287	}
