289	export async function getPlacementDetails(
290	  department_degree_id: number,
291	  group_id: number,
292	): Promise<PlacementData | null> {
293	  logger.info(
294	    `\n[DB-DEBUG] 🚀 Starting fetch for department_degree_id: "${department_degree_id}"`,
295	  );
296	  logger.info(`\n[DB-DEBUG] 🚀 Starting fetch for group_id: "${group_id}"`);
297	
298	  if (process.env.MOCK_DB === 'true') {
299	    logger.info('[DB-DEBUG] Mocking Placement Details');
300	    return {
301	      department_name: 'Mock Dept',
302	      degree_type: 'Mock Degree',
303	      exam_start_date: new Date().toISOString(),
304	      total_students: 10,
305	      group_name: 'Mock Group',
306	      report_title: 'Mock Report',
307	      exam_ref_no: 'MOCK-REF',
308	      department_id: 1,
309	      degree_type_id: 1,
310	      department_deg_id: 1,
311	      trait_distribution: [],
312	    } as PlacementData;
313	  }
314	
315	  const client = await getPool().connect();
316	
317	  try {
318	    const query = `
319	            WITH DuplicateCheck AS (
320	SELECT 
321	    full_name, 
322	    department_degree_id
323	FROM registrations
324	WHERE department_degree_id = $2
325	GROUP BY full_name, department_degree_id
326	HAVING COUNT(*) > 1
327	),
328	RawStudentData AS (
329	SELECT 
330	    aa.user_id,
331	    dpt.name AS "department_name",
332	    dt.name AS "degree_type",
333	    a1.started_at,
334	    gp.name AS "group_name",
335	    pt.code AS "trait_code",
336	    pt.id AS "trait_id",
337	    pt.blended_style_name,
338	    pt.blended_style_desc,
339	    aa.registration_id,
340	    r.full_name,
341	    r.metadata ->> 'currentYear' as "current_year",
342	    r.mobile_number,
343	    pt.color_rgb,
344	    ar.report_number,
345	    ar.agile_scores,
346	    a1.group_id,
347	    aa.metadata,
348	    aa.status,
349	    aa.assessment_level_id,
350	    r.department_degree_id,
351	    dpt.id AS department_id,
352	    dt.id AS degree_type_id,
353	    -- Check against the duplicate list
354	    CASE 
355	        WHEN dc.full_name IS NOT NULL THEN true 
356	        ELSE false 
357	    END AS is_duplicate_name
358	FROM assessment_attempts aa
359	JOIN assessment_sessions a1 ON aa.assessment_session_id = a1.id
360	JOIN registrations r ON aa.registration_id = r.id
361	JOIN department_degrees dd ON r.department_degree_id = dd.id
362	JOIN departments dpt ON dd.department_id = dpt.id
363	JOIN degree_types dt ON dd.degree_type_id = dt.id
364	JOIN groups gp ON a1.group_id = gp.id
365	JOIN assessment_reports ar ON aa.assessment_session_id = ar.assessment_session_id
366	LEFT JOIN personality_traits pt ON aa.dominant_trait_id = pt.id 
367	LEFT JOIN DuplicateCheck dc 
368	    ON r.full_name = dc.full_name 
369	    AND r.department_degree_id = dc.department_degree_id
370	WHERE 
371	    a1.group_id = $1
372	    AND r.department_degree_id = $2
373	    AND aa.status = 'COMPLETED'
374	),
375	TraitGrouped AS (
376	SELECT
377	    trait_id,
378	    trait_code,
379	    blended_style_name,
380	    blended_style_desc,
381	    color_rgb,
382	    COUNT(user_id) AS trait_student_count,
383	    JSON_AGG(
384	        CASE 
385	            WHEN is_duplicate_name IS TRUE THEN
386	                JSON_BUILD_OBJECT(
387	                    'registration_ID', registration_id,
388	                    'full_name', full_name,
389	                    'college_year', current_year,
390	                    'student_exam_ref_no', report_number,
391	                    'duplicate_name', true,
392	                    'mobile_number', mobile_number,
393	                    'agile_score', agile_scores -- << CHANGED: Added agile_score to JSON object
394	                )
395	            ELSE
396	                JSON_BUILD_OBJECT(
397	                    'registration_ID', registration_id,
398	                    'full_name', full_name,
399	                    'college_year', current_year,
400	                    'student_exam_ref_no', report_number,
401	                    'agile_score', agile_scores -- << CHANGED: Added agile_score to JSON object
402	                )
403	        END
404	    ) AS students_data,
405	    MAX(department_name) as department_name,
406	    MAX(degree_type) as degree_type,
407	    MAX(started_at) as exam_start_date,
408	    MAX(group_name) as group_name,
409	    MAX(report_number) as report_number,
410	    MAX(department_id) as department_id,
411	    MAX(degree_type_id) as degree_type_id,
412	    MAX(department_degree_id) as department_deg_id
413	FROM RawStudentData
414	WHERE trait_code IS NOT NULL
415	GROUP BY trait_id, trait_code, blended_style_name, blended_style_desc, color_rgb
416	)
417	SELECT 
418	JSON_BUILD_OBJECT(
419	    'department_name', MAX(department_name),
420	    'degree_type', MAX(degree_type),
421	    'exam_start_date', MAX(exam_start_date),
422	    'total_students', COALESCE(SUM(trait_student_count), 0),
423	    'group_name', MAX(group_name),
424	    'report_title', CONCAT('Students Handbook ', EXTRACT(YEAR FROM MAX(exam_start_date))),
425	    'exam_ref_no', MAX(report_number),
426	    'department_id', MAX(department_id),
427	    'degree_type_id', MAX(degree_type_id),
428	    'department_deg_id', MAX(department_deg_id),
429	    'trait_distribution', COALESCE(
430	        JSON_AGG(
431	            JSON_BUILD_OBJECT(
432	                'trait_ID', trait_id,
433	                'trait_code', trait_code,
434	                'blended_style_name', blended_style_name,
435	                'blended_style_desc', blended_style_desc,
436	                'student_count', trait_student_count,
437	                'students_data', students_data,
438	                'color_rgb', string_to_array(color_rgb, ',')::int[]
439	            )
440	        ) FILTER (WHERE trait_id IS NOT NULL), '[]'
441	    )
442	) AS final_json_output
443	FROM TraitGrouped;
444	        `;
445	
446	    const result = await client.query(query, [group_id, department_degree_id]);
447	
448	    const data = result.rows[0]?.final_json_output;
449	
450	    if (!data || !data.department_name) {
451	      logger.warn(`[DB-DEBUG] ⚠️ No data found for group: ${group_id}`);
452	      return null;
453	    }
454	
455	    logger.info(
456	      `[DB-DEBUG] ✅ Successfully fetched placement details. Total Students: ${data.total_students}`,
457	    );
458	
459	    return data as PlacementData;
460	  } catch (error) {
461	    logger.error('[DB-DEBUG] ❌ SQL ERROR:', error);
462	    throw error;
463	  } finally {
464	    client.release();
465	    logger.info(`[DB-DEBUG] DB Connection released.\n`);
466	  }
467	}
