469	export async function updateReportPassword(
470	  assessmentSessionId: string,
471	  password: string,
472	): Promise<string> {
473	  // Changed return type to Promise<string>
474	
475	  if (process.env.MOCK_DB === 'true') {
476	    logger.info(
477	      `[DB-MOCK] Checking/Updating report password for session: ${assessmentSessionId}. New would be: ${password}`,
478	    );
479	    // In mock mode, we can simulate either case. Let's simulate "new password used" for simplicity,
480	    // or return a fixed mock string if we wanted to test "existing".
481	    // For now, return the passed password to simulate "first time generation".
482	    return password;
483	  }
484	
485	  const client = await getPool().connect();
486	
487	  try {
488	    // 1. Check if password already exists
489	    const checkQuery = `
490	            SELECT report_password 
491	            FROM assessment_reports 
492	            WHERE assessment_session_id = $1
493	        `;
494	    const checkResult = await client.query(checkQuery, [assessmentSessionId]);
495	
496	    if (checkResult.rows.length > 0) {
497	      const existingPassword = checkResult.rows[0].report_password;
498	      if (existingPassword.trim().length >= 5) {
499	        logger.info(
500	          `[DB] Found existing valid password for session: ${assessmentSessionId}`,
501	        );
502	        return existingPassword;
503	      }
504	    }
505	
506	    // 2. If not exists (or empty), update with new password
507	    const updateQuery = `
508	            UPDATE assessment_reports 
509	            SET report_password = $1 
510	            WHERE assessment_session_id = $2
511	        `;
512	    await client.query(updateQuery, [password, assessmentSessionId]);
513	    logger.info(
514	      `[DB] Updated report password for session: ${assessmentSessionId}`,
515	    );
516	    return password;
517	  } catch (error) {
518	    logger.error(
519	      `[DB] Failed to update/fetch report password for session: ${assessmentSessionId}`,
520	      error,
521	    );
522	    throw error;
523	  } finally {
524	    client.release();
525	  }
526	}
