508	  private getCircleRoleTypography(
509	    roleName: string,
510	    circleR: number,
511	  ): { fontSize: number; lineHeight: number; lines: string[] } {
512	    const label = this.getCircleDisplayRole(roleName);
513	    const maxWidth = circleR * 2 - 8;
514	    const maxHeight = circleR * 2 - 16;
515	    const sizes = [9.2, 8.6, 8, 7.4, 6.8, 6.2, 5.8];
516	
517	    for (const fontSize of sizes) {
518	      this.doc.font(this.FONT_SORA_BOLD).fontSize(fontSize);
519	      const lines = this.buildCircleRoleLinesExact(label, maxWidth, 3);
520	      if (!lines) continue;
521	
522	      const lineHeight = fontSize + 0.9;
523	      const textHeight = lines.length * lineHeight;
524	      const widestLine = Math.max(
525	        ...lines.map((line) => this.doc.widthOfString(line)),
526	      );
527	
528	      if (widestLine <= maxWidth && textHeight <= maxHeight) {
529	        return { fontSize, lineHeight, lines };
530	      }
531	    }
532	
533	    this.doc.font(this.FONT_SORA_BOLD).fontSize(6.4);
534	    const exactFallback = this.buildCircleRoleLinesExact(label, maxWidth, 4);
535	    if (exactFallback) {
536	      return {
537	        fontSize: 6.4,
538	        lineHeight: 7.2,
539	        lines: exactFallback,
540	      };
541	    }
542	
543	    return {
544	      fontSize: 6.4,
545	      lineHeight: 7.2,
546	      lines: this.buildCircleRoleLines(label, maxWidth, 3),
547	    };
548	  }
