550	  private buildCircleRoleLinesExact(
551	    value: string,
552	    maxWidthPerLine: number,
553	    maxLines: number,
554	  ): string[] | null {
555	    const clean = this.cleanRoleLabel(value);
556	    const words = clean.split(' ').filter(Boolean);
557	    if (!words.length) return ['Role'];
558	
559	    const lines: string[] = [];
560	    let current = '';
561	
562	    for (const word of words) {
563	      if (this.doc.widthOfString(word) > maxWidthPerLine) return null;
564	
565	      const candidate = current ? `${current} ${word}` : word;
566	      if (this.doc.widthOfString(candidate) <= maxWidthPerLine) {
567	        current = candidate;
568	        continue;
569	      }
570	
571	      if (current) lines.push(current);
572	      if (lines.length >= maxLines) return null;
573	      current = word;
574	    }
575	
576	    if (current) lines.push(current);
577	    return lines.length <= maxLines ? lines : null;
578	  }
