846	  private buildCircleRoleLines(
847	    value: string,
848	    maxWidthPerLine: number,
849	    maxLines: number,
850	  ): string[] {
851	    const clean = this.cleanRoleLabel(value);
852	    const words = clean.split(' ').filter(Boolean);
853	    if (!words.length) return ['Role'];
854	
855	    const lines: string[] = [];
856	    let current = '';
857	
858	    words.forEach((word) => {
859	      if (lines.length >= maxLines) return;
860	
861	      const candidate = current ? `${current} ${word}` : word;
862	      if (this.doc.widthOfString(candidate) <= maxWidthPerLine) {
863	        current = candidate;
864	        return;
865	      }
866	
867	      if (current) {
868	        lines.push(current);
869	        current = '';
870	      }
871	
872	      if (this.doc.widthOfString(word) <= maxWidthPerLine) {
873	        current = word;
874	      } else {
875	        lines.push(this.fitPhraseToLength(word, 10));
876	      }
877	    });
878	
879	    if (current && lines.length < maxLines) {
880	      lines.push(current);
881	    }
882	
883	    return lines.slice(0, maxLines);
884	  }
