886	  private buildCompactListLine(
887	    raw: string,
888	    maxChars: number,
889	    maxItems: number,
890	  ): string {
891	    const items = String(raw || '')
892	      .split(/,|\/|\||;|\band\b/gi)
893	      .map((item) => this.cleanRoleLabel(item))
894	      .filter(Boolean);
895	
896	    if (!items.length) {
897	      return this.fitPhraseToLength(String(raw || '').trim(), maxChars);
898	    }
899	
900	    const limit = Math.max(1, Math.min(maxItems, items.length));
901	    for (let count = limit; count >= 1; count -= 1) {
902	      const line = items.slice(0, count).join(', ');
903	      if (line.length <= maxChars) return line;
904	    }
905	
906	    return this.fitPhraseToLength(items[0], maxChars);
907	  }
