export interface AnswerTypeCount {
  ANSWER_TYPE: 'D' | 'I' | 'S' | 'C';
  COUNT: number;
}

export interface AgileScore {
  focus: number;
  courage: number;
  respect: number;
  openness: number;
  commitment: number;
}

export interface CollegeData {
  full_name: string;
  email_id: string;
  exam_start: string;
  exam_end: string;
  bi_registration_ID: string;
  assigned_exam_id: string;
  exam_ref_no: string;
  report_title: string;
  score_D: number;
  score_I: number;
  score_S: number;
  score_C: number;
  department_deg_id?: number;
  dept_code?: string;
  group_name?: string;
  most_answered_answer_type: AnswerTypeCount[];
  top_answered_types: any[];
  program_type: number;
  agile_scores: AgileScore[];
  report_password?: string;
}

export interface SchoolData {
  full_name: string;
  email_id: string;
  exam_start: string;
  exam_end: string;
  bi_registration_ID: string;
  assigned_exam_id: string;
  exam_ref_no: string;
  report_title: string;
  score_D: number;
  score_I: number;
  score_S: number;
  score_C: number;
  school_level_id: number;
  school_stream_id?: number;
  most_answered_answer_type: AnswerTypeCount[];
  top_answered_types: any[];
  program_type: number;
  agile_scores: AgileScore[];
  report_password?: string;
  dept_code?: string;
  group_name?: string;
  student_board?: string;
}

export interface EmployeeData {
  full_name: string;
  email_id: string;
  exam_start: string;
  exam_end: string;
  bi_registration_ID: string;
  assigned_exam_id: string;
  exam_ref_no: string;
  report_title: string;
