      .font(this.FONT_SORA_BOLD)
      .fontSize(20)
      .fillColor(this.COLOR_DEEP_BLUE)
      .text('Origin BI MBA SpecFit', x, y + 14, {
        width: w * 0.62,
        lineBreak: false,
        ellipsis: true,
      });

