    const metaW = w * 0.38;

    this.doc
      .font(this.FONT_SORA_BOLD)
      .fontSize(13)
      .fillColor(this.COLOR_BLACK)
      .text(this.data.full_name || '-', metaX, y + 14, {
        width: metaW,
        align: 'right',
        lineBreak: false,
        ellipsis: true,
